import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';

const Home = () => {
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTours = async () => {
      try {
        // 呼叫你寫好的後端 API
        const response = await axiosInstance.get('/api/tours');
        setTours(response.data);
        setLoading(false);
      } catch (error) {
        console.error('無法抓取行程資料:', error);
        setLoading(false);
      }
    };
    fetchTours();
  }, []);

  if (loading) return <div className="text-center mt-10">Loading adventures...</div>;

  return (
    <div className="container mx-auto p-6">
      {/* 歡迎標語 */}
      <header className="text-center mb-12">
        <h1 className="text-4xl font-extrabold text-indigo-900 mb-2">
          Explore Our Featured Tours
        </h1>
        <p className="text-gray-600">Find the perfect trip for your next Australian getaway.</p>
      </header>

      {/* 旅遊行程卡片網格 */}
      {tours.length === 0 ? (
        <p className="text-center text-gray-500">No tours available at the moment. Check back later!</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {tours.map((tour) => (
            <div key={tour._id} className="bg-white rounded-2xl shadow-md hover:shadow-xl transition-shadow duration-300 overflow-hidden border border-gray-100 flex flex-col">
              {/* 這裡可以放一張預設圖片，讓畫面更專業 */}
              <div className="h-48 bg-indigo-100 flex items-center justify-center">
                <span className="text-5xl">🏝️</span>
              </div>

              <div className="p-6 flex-grow">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="text-xl font-bold text-gray-800">{tour.title}</h3>
                  <span className="text-lg font-bold text-green-600">${tour.price}</span>
                </div>

                <p className="text-gray-600 text-sm mb-4 line-clamp-3">
                  {tour.description || "Join us for an unforgettable journey through Australia's most beautiful landscapes."}
                </p>

                <div className="flex items-center text-xs text-gray-400 font-medium uppercase tracking-wider">
                  <span className="mr-3">⏱ {tour.duration || 'Flexible'}</span>
                  <span>📍 Australia</span>
                </div>
              </div>

              <div className="p-6 pt-0">
                <button className="w-full bg-indigo-600 text-white font-bold py-2 rounded-lg hover:bg-indigo-700 transition">
                  Book This Tour
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Home;
